/**
 * Redeploy PredictionMarket V2 contracts with multi-vote support.
 *
 * Reads wallet keys and token addresses from test-wallets.json,
 * deploys new market contracts with the updated bytecode,
 * calls createMarket on each, then updates test-wallets.json and podConfig.ts.
 *
 * Usage:
 *   npx tsx solutions/redeploy-markets.ts
 */

import { createWalletClient, createPublicClient, http, formatEther } from "viem";
import { baseSepolia } from "viem/chains";
import { privateKeyToAccount } from "viem/accounts";
import { readFileSync, writeFileSync } from "fs";
import { resolve } from "path";

const RPC_URL = "https://base-sepolia-rpc.publicnode.com";

const predictionMarketAbi = [
  {
    type: "constructor",
    inputs: [
      { name: "owner_", type: "address" },
      { name: "token_", type: "address" },
    ],
    stateMutability: "nonpayable",
  },
  {
    type: "function",
    name: "createMarket",
    inputs: [{ name: "question", type: "string" }],
    outputs: [{ name: "marketId", type: "uint256" }],
    stateMutability: "nonpayable",
  },
  {
    type: "function",
    name: "markets",
    inputs: [{ name: "", type: "uint256" }],
    outputs: [
      { name: "question", type: "string" },
      { name: "yesPool", type: "uint256" },
      { name: "noPool", type: "uint256" },
      { name: "resolved", type: "bool" },
      { name: "outcome", type: "bool" },
    ],
    stateMutability: "view",
  },
] as const;

// New V2 bytecode — compiled from solutions/PredictionMarketV2.sol (allows repeat voting)
const PREDICTION_MARKET_V2_BYTECODE = "" as `0x${string}`;

async function main() {
  const solutionsDir = resolve(import.meta.dirname ?? __dirname, ".");

  // Read existing wallet data
  const walletsPath = resolve(solutionsDir, "test-wallets.json");
  const wallets = JSON.parse(readFileSync(walletsPath, "utf-8")) as Array<{
    owner: string;
    privateKey: `0x${string}`;
    address: string;
    tokenAddress: `0x${string}`;
    tokenSymbol: string;
    marketAddress: string;
    question: string;
  }>;

  const publicClient = createPublicClient({ chain: baseSepolia, transport: http(RPC_URL) });

  for (const w of wallets) {
    console.log(`\n━━━ ${w.owner} ━━━`);
    const account = privateKeyToAccount(w.privateKey as `0x${string}`);
    console.log(`  Wallet: ${account.address}`);
    console.log(`  Token:  ${w.tokenAddress}`);
    console.log(`  Old Market: ${w.marketAddress}`);

    const balance = await publicClient.getBalance({ address: account.address });
    console.log(`  Balance: ${formatEther(balance)} ETH`);
    if (balance === 0n) {
      console.error(`  ✗ No ETH — cannot deploy`);
      process.exit(1);
    }

    const walletClient = createWalletClient({ account, chain: baseSepolia, transport: http(RPC_URL) });
    const nonce = await publicClient.getTransactionCount({ address: account.address });
    console.log(`  Current nonce: ${nonce}`);

    // Deploy new market contract
    console.log(`  Deploying new PredictionMarket V2 (multi-vote)...`);
    const deployHash = await walletClient.deployContract({
      abi: predictionMarketAbi,
      bytecode: PREDICTION_MARKET_V2_BYTECODE,
      args: [account.address, w.tokenAddress],
      nonce: nonce,
    });
    console.log(`  Deploy tx: ${deployHash}`);
    const receipt = await publicClient.waitForTransactionReceipt({ hash: deployHash });
    const newMarketAddress = receipt.contractAddress!;
    console.log(`  ✓ New Market: ${newMarketAddress}`);

    // Create market question
    console.log(`  Creating market: "${w.question}"`);
    const createHash = await walletClient.writeContract({
      address: newMarketAddress,
      abi: predictionMarketAbi,
      functionName: "createMarket",
      args: [w.question],
      nonce: nonce + 1,
    });
    await publicClient.waitForTransactionReceipt({ hash: createHash });
    console.log(`  ✓ Market question created (id: 0)`);

    // Verify market data
    const marketData = await publicClient.readContract({
      address: newMarketAddress,
      abi: predictionMarketAbi,
      functionName: "markets",
      args: [0n],
    });
    console.log(`  ✓ Verified question: "${marketData[0]}"`);

    w.marketAddress = newMarketAddress;
  }

  // Write updated test-wallets.json
  writeFileSync(walletsPath, JSON.stringify(wallets, null, 2) + "\n");
  console.log(`\nWrote ${walletsPath}`);

  // Write updated podConfig.ts
  const podConfigPath = resolve(solutionsDir, "podConfig.ts");
  const podConfigContent = `export type PodMarket = {
  owner: string;
  marketAddress: \`0x\${string}\`;
  tokenAddress: \`0x\${string}\`;
};

export const POD_MARKETS: PodMarket[] = [
${wallets
  .map(
    (w) => `  {
    owner: "${w.owner}",
    marketAddress: "${w.marketAddress}",
    tokenAddress: "${w.tokenAddress}",
  },`
  )
  .join("\n")}
];
`;
  writeFileSync(podConfigPath, podConfigContent);
  console.log(`Wrote ${podConfigPath}`);

  console.log("\n━━━ Summary ━━━");
  for (const w of wallets) {
    console.log(`  ${w.owner}: ${w.marketAddress}`);
  }
  console.log("\nDone! New markets support multi-vote.");
}

main().catch((err) => {
  console.error("Fatal error:", err.message ?? err);
  process.exit(1);
});
